function solve(n, m, sources) {
    // Initialize distance and color grids. 
    // We use Infinity for distance and 0 for color (uncolored).
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));
    const colorGrid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Queue for BFS. Stores [r, c].
    const queue = [];

    // 1. Initialization (Time T=0)
    for (const source of sources) {
        const r = source[0];
        const c = source[1];
        const color = source[2];

        if (dist[r][c] === Infinity) {
            dist[r][c] = 0;
            colorGrid[r][c] = color;
            queue.push([r, c]);
        } else {
            // If multiple sources start at the same point (though constraints say they don't), take max color
            colorGrid[r][c] = Math.max(colorGrid[r][c], color);
        }
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 2. Layered BFS
    let head = 0;
    while (head < queue.length) {
        const layerSize = queue.length - head;

        // Stores candidates for the next layer: key = "r,c", value = list of incoming colors
        const nextLayerCandidates = new Map();

        // Process current layer (time T)
        for (let i = 0; i < layerSize; i++) {
            const [r, c] = queue[head++];
            const currentT = dist[r][c];
            const propagatedColor = colorGrid[r][c];
            const nextT = currentT + 1;

            // Propagate to neighbors
            for (const [dr, dc] of directions) {
                const nr = r + dr;
                const nc = c + dc;

                if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                    // If this neighbor hasn't been reached yet
                    if (dist[nr][nc] === Infinity) {
                        // Record potential arrival at time nextT
                        const key = `${nr},${nc}`;
                        if (!nextLayerCandidates.has(key)) {
                            nextLayerCandidates.set(key, []);
                        }
                        nextLayerCandidates.get(key).push(propagatedColor);
                    }
                }
            }
        }

        // Finalize assignments for the next layer (time T+1)
        const nextQueue = [];
        for (const [key, colors] of nextLayerCandidates.entries()) {
            const [nr, nc] = key.split(',').map(Number);

            // Since we are processing layer by layer, all cells in nextLayerCandidates 
            // are reached for the first time at time nextT.
            dist[nr][nc] = nextT;

            // Determine the final color: maximum of all incoming colors
            const finalColor = Math.max(...colors);
            colorGrid[nr][nc] = finalColor;

            nextQueue.push([nr, nc]);
        }

        // Move to the next layer
        queue.push(...nextQueue);
    }

    return colorGrid;
}

